import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface UsageBreakdown {
  category: string;
  usage: number;
}

interface BatteryStatusData {
  status: {
    chargeLevel: number;
    timeRemaining: string;
  };
  usageBreakdown: UsageBreakdown[];
}

export default function Widget() {
  const batteryData = response.data as BatteryStatusData;
  const { status, usageBreakdown } = batteryData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#333' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FFEB3B', mb: 0.5 }}>
              Battery Monitor
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ color: '#4CAF50', my: 0.5 }}>
              {status.chargeLevel}%
            </Typography>
            <Typography variant="body1" sx={{ color: '#FFEB3B' }}>
              {status.timeRemaining} remaining
            </Typography>
          </Box>

          <PieChart
            height={120}
            series={[
              {
                data: usageBreakdown.map((item) => item.usage),
                color: ['#FFEB3B', '#4CAF50', '#8BC34A'],
                labels: usageBreakdown.map((item) => item.category),
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieSlice-root': {
                strokeWidth: 0,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {usageBreakdown.map((item, index) => (
              <Chip
                key={index}
                label={`${item.category}: ${item.usage}%`}
                sx={{ fontSize: '11px', bgcolor: '#4CAF50', color: '#FFF', px: 1 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
